import React from 'react'

const Dashboard = React.lazy(() => import('./views/dashboard/Dashboard'))
const Applications = React.lazy(() => import('./views/pages/Applications'))
const UnofficialApplications = React.lazy(() => import('./views/pages/UnofficialApplications'))
const AppForm = React.lazy(() => import('./views/pages/AppForm'))
const Settings = React.lazy(() => import('./views/pages/Settings'))
const Payments = React.lazy(() => import('./views/pages/Payments'))

const routes = [
  { path: '/', exact: true, name: 'Home' },
  { path: '/dashboard', name: 'Dashboard', component: Dashboard },
  { path: '/payment', name: 'Payments', component: Payments, exact: true },
  { path: '/settings', name: 'Account Settings', component: Settings, exact: true },
  { path: '/application', name: 'Applications', component: Applications, exact: true },
  {
    path: '/application/official',
    name: 'Official Applications',
    component: Applications,
  },
  {
    path: '/application/unofficial',
    name: 'Unofficial Applications',
    component: UnofficialApplications,
  },
  { path: '/application/form', name: 'Application Form', component: AppForm },
]

export default routes
